					$b_priority = array_search( $b, $priority_order );

					if ( false === $a_priority ) {
						$a_priority = PHP_INT_MAX;
					}
					if ( false === $b_priority ) {
						$b_priority = PHP_INT_MAX;
					}

					return $a_priority - $b_priority;
				} 
